"use client";

import { useState, useEffect, useMemo, Suspense } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { Search, SlidersHorizontal, X, ChevronDown, ChevronUp } from "lucide-react";
import Footer from "@/components/Footer";
import { productsData, CATEGORY_TREE, packLabel, type Product } from "@/app/products/product data";

// ─── Helpers ──────────────────────────────────────────────────────────────────

function certStyle(cert: string): "green" | "amber" | "neutral" | "none" {
    if (!cert) return "none";
    if (cert.toLowerCase().includes("under process")) return "amber";
    if (
        cert.toLowerCase().includes("not required") ||
        cert.toLowerCase().includes("usfda") ||
        cert.toLowerCase().includes("eu approved")
    ) return "neutral";
    return "green";
}

const SANITIZER_PRODUCT_IDS = new Set([23, 22, 21]);

function isSanitizerProduct(p: Product) {
    return SANITIZER_PRODUCT_IDS.has(p.id);
}

const domainHero: Record<string, { image: string; title: string; tagline: string; overlay: string }> = {
    Aquaculture: {
        image: "/product/sadf.png",
        title: "Aquaculture Products",
        tagline: "Science-led solutions for thriving ponds & shrimp farms",
        overlay: "from-sky-900/85 via-sky-800/60 to-transparent",
    },
    Poultry: {
        image: "/images/poultry.jpeg",
        title: "Poultry Products",
        tagline: "Optimised nutrition & health solutions for poultry farming",
        overlay: "from-amber-900/85 via-amber-800/60 to-transparent",
    },
    Cattle: {
        image: "/images/cattle.jpeg",
        title: "Cattle Products",
        tagline: "Premium supplements & health products for livestock excellence",
        overlay: "from-green-900/85 via-green-800/60 to-transparent",
    },
};

// Fixed domain list — always show all three tabs regardless of product data
const ALL_DOMAINS = ["Aquaculture", "Poultry", "Cattle"];

// Domains whose products are still being manufactured / not yet available
const COMING_SOON_DOMAINS = new Set(["Poultry", "Cattle"]);

// ─── ComingSoon ───────────────────────────────────────────────────────────────

function ComingSoon({ domain }: { domain: string }) {
    const config: Record<string, {
        icon: string;
        accentText: string;
        accentBg: string;
        badgeBg: string;
        badgeBorder: string;
        progressGradient: string;
        glowColor: string;
        progressPct: string;
        progressNote: string;
    }> = {
        Poultry: {
            icon: "🐔",
            accentText: "text-amber-700",
            accentBg: "from-amber-50 via-orange-50 to-yellow-50",
            badgeBg: "bg-amber-100",
            badgeBorder: "border-amber-200",
            progressGradient: "from-amber-400 to-orange-500",
            glowColor: "bg-amber-300",
            progressPct: "65%",
            progressNote: "Product lineup being finalised",
        },
        Cattle: {
            icon: "🐄",
            accentText: "text-green-700",
            accentBg: "from-green-50 via-emerald-50 to-teal-50",
            badgeBg: "bg-green-100",
            badgeBorder: "border-green-200",
            progressGradient: "from-green-400 to-emerald-500",
            glowColor: "bg-green-300",
            progressPct: "40%",
            progressNote: "Formulation & trials underway",
        },
    };

    const c = config[domain] ?? config["Poultry"];

    return (
        <div className="flex-1 flex items-start justify-center pt-4">
            <div className={`w-full max-w-2xl bg-gradient-to-br ${c.accentBg} border-2 ${c.badgeBorder} rounded-3xl px-10 py-14 flex flex-col items-center text-center shadow-sm`}>

                {/* Icon */}
                <div className="relative mb-6">
                    <div className={`absolute inset-0 rounded-full blur-2xl opacity-30 ${c.glowColor}`} />
                    <div className="relative w-24 h-24 rounded-full bg-white flex items-center justify-center shadow-md border border-white/80 text-5xl">
                        {c.icon}
                    </div>
                </div>

                {/* Badge */}
                <span className={`inline-flex items-center gap-2 text-xs font-bold tracking-widest uppercase px-4 py-1.5 rounded-full mb-5 ${c.badgeBg} ${c.accentText} border ${c.badgeBorder}`}>
                    <span className="w-1.5 h-1.5 rounded-full bg-current animate-pulse" />
                    Products Under Manufacturing
                </span>

                <h2 className="text-3xl font-black leading-tight mb-3 text-gray-900">
                    {domain} Range<br />
                    <span className={c.accentText}>Launching Soon</span>
                </h2>

                <p className="text-gray-500 text-sm leading-relaxed max-w-md mb-8">
                    Our R&amp;D team is actively manufacturing and conducting quality trials on our{" "}
                    <span className="font-semibold text-gray-700">{domain.toLowerCase()} healthcare product line</span>.
                    Expect the same science-led quality and efficacy that defines every Innovare Biopharma product.
                </p>

                {/* Progress */}
                <div className="w-full max-w-xs mb-2">
                    <div className="flex justify-between text-[11px] font-semibold text-gray-400 mb-1.5">
                        <span>Manufacturing Progress</span>
                        <span className={c.accentText}>In Progress</span>
                    </div>
                    <div className="h-2 rounded-full bg-white border border-gray-200 overflow-hidden">
                        <div
                            className={`h-full rounded-full bg-gradient-to-r ${c.progressGradient}`}
                            style={{ width: c.progressPct }}
                        />
                    </div>
                </div>
                <p className="text-[11px] text-gray-400 mb-8">{c.progressNote}</p>

                {/* What to expect */}
                <div className="w-full bg-white/60 border border-white/80 rounded-2xl px-6 py-5 mb-8 text-left">
                    <p className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-3">What to expect</p>
                    <ul className="space-y-2">
                        {[
                            "Clinically validated formulations",
                            "Comprehensive dosage & usage guidelines",
                            "Certified by relevant regulatory bodies",
                            "Full product catalogue with technical data sheets",
                        ].map((item) => (
                            <li key={item} className="flex items-center gap-2.5 text-sm text-gray-600">
                                <span className={`w-4 h-4 rounded-full flex items-center justify-center flex-shrink-0 ${c.badgeBg}`}>
                                    <svg width="8" height="8" viewBox="0 0 10 10" fill="none">
                                        <path d="M1.5 5l3 3 4-5.5" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" className={c.accentText} />
                                    </svg>
                                </span>
                                {item}
                            </li>
                        ))}
                    </ul>
                </div>

                <div className="w-full border-t border-dashed border-gray-200 mb-6" />

                <p className="text-xs text-gray-400 font-medium">
                    Interested in {domain.toLowerCase()} solutions?{" "}
                    <a
                        href="/contact"
                        className={`font-bold underline underline-offset-2 ${c.accentText} hover:opacity-70 transition-opacity`}
                    >
                        Contact our team →
                    </a>
                </p>
            </div>
        </div>
    );
}

// ─── CategoryFilterSection ────────────────────────────────────────────────────

function CategoryFilterSection({
    category, subcategories, selectedCategory, selectedSubcategory,
    onSelectCategory, onSelectSubcategory, domainProducts,
}: {
    category: string; subcategories: string[];
    selectedCategory: string; selectedSubcategory: string;
    onSelectCategory: (c: string) => void;
    onSelectSubcategory: (s: string) => void;
    domainProducts: Product[];
}) {
    const isOpen = selectedCategory === category;
    const categoryCount = domainProducts.filter(p => p.category === category).length;
    if (categoryCount === 0) return null;

    return (
        <div className="mb-1">
            <button
                onClick={() => onSelectCategory(isOpen ? "" : category)}
                className={`w-full flex items-center justify-between px-3 py-2.5 rounded-xl transition-all group ${
                    isOpen ? "bg-[#2A5DA8] text-white" : "hover:bg-blue-50 text-gray-700"
                }`}
            >
                <span className="text-[13px] font-semibold text-left leading-tight">{category}</span>
                <div className="flex items-center gap-2 flex-shrink-0">
                    <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-full ${isOpen ? "bg-white/20 text-white" : "bg-gray-100 text-gray-500"}`}>
                        {categoryCount}
                    </span>
                    {isOpen
                        ? <ChevronUp size={13} className="text-white/80" />
                        : <ChevronDown size={13} className="text-gray-400 group-hover:text-[#2A5DA8]" />
                    }
                </div>
            </button>

            {isOpen && subcategories.length > 0 && (
                <div className="ml-3 mt-1 flex flex-col gap-0.5 border-l-2 border-blue-100 pl-3">
                    {subcategories.map(sub => {
                        const subCount = domainProducts.filter(p => p.category === category && p.subcategory === sub).length;
                        if (subCount === 0) return null;
                        const active = selectedSubcategory === sub;
                        return (
                            <button
                                key={sub}
                                onClick={() => onSelectSubcategory(active ? "" : sub)}
                                className={`w-full flex items-center justify-between px-2.5 py-2 rounded-lg transition-all text-left ${active ? "bg-sky-100 text-[#2A5DA8] font-semibold" : "text-gray-600 hover:bg-gray-50 hover:text-gray-800"}`}
                            >
                                <span className="text-[12px] leading-tight">{sub}</span>
                                <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-full flex-shrink-0 ${active ? "bg-[#2A5DA8]/10 text-[#2A5DA8]" : "bg-gray-100 text-gray-400"}`}>
                                    {subCount}
                                </span>
                            </button>
                        );
                    })}
                </div>
            )}
        </div>
    );
}

// ─── ProductCard ──────────────────────────────────────────────────────────────

function ProductCard({ product, onClick }: { product: Product; onClick: () => void }) {
    const cs = certStyle(product.certificate);
    const certClasses: Record<string, string> = {
        green: "bg-green-50 text-green-700 border border-green-200",
        amber: "bg-amber-50 text-amber-700 border border-amber-200",
        neutral: "bg-sky-50 text-sky-700 border border-sky-200",
        none: "",
    };

    return (
        <div
            onClick={onClick}
            className="bg-white rounded-2xl border-2 border-gray-100 overflow-hidden hover:shadow-2xl hover:border-[#2A5DA8]/20 hover:-translate-y-1.5 cursor-pointer transition-all duration-300 group flex flex-col"
        >
            <div
                className="bg-gradient-to-br from-[#e8f0fe] via-[#dbeafe] to-[#eff6ff] flex justify-center items-center flex-shrink-0"
                style={{ height: "280px" }}
            >
                <div className="relative flex items-center justify-center" style={{ width: "220px", height: "220px" }}>
                    <svg viewBox="0 0 220 220" className="absolute inset-0 w-full h-full drop-shadow-lg">
                        <defs>
                            <linearGradient id={`hg${product.id}`} x1="0%" y1="0%" x2="100%" y2="100%">
                                <stop offset="0%" stopColor="#ffffff" />
                                <stop offset="100%" stopColor="#bfdbfe" />
                            </linearGradient>
                        </defs>
                        <path
                            d="M80 12 L140 12 Q162 12 174 32 L206 90 Q218 110 206 130 L174 188 Q162 208 140 208 L80 208 Q58 208 46 188 L14 130 Q2 110 14 90 L46 32 Q58 12 80 12 Z"
                            fill={`url(#hg${product.id})`}
                            stroke="#2A5DA8"
                            strokeWidth="4.5"
                        />
                    </svg>
                    <img
                        src={product.image}
                        alt={product.name}
                        className="relative z-10 object-contain group-hover:scale-110 transition-transform duration-300"
                        style={{ width: "140px", height: "140px" }}
                    />
                </div>
            </div>

            <div className="flex flex-col flex-1 px-5 pt-4 pb-5 gap-1.5">
                <h3 className="font-bold text-gray-900 text-base leading-snug text-center line-clamp-2 min-h-[3rem]">
                    {product.name}
                </h3>
                <p className="text-sm text-[#2A5DA8] font-semibold text-center leading-tight line-clamp-1">
                    {product.composition}
                </p>

                <div className="flex justify-center min-h-[1.6rem]">
                    {cs !== "none" ? (
                        <span className={`inline-flex items-center gap-1 text-[10px] font-bold px-2.5 py-1 rounded-full tracking-wide truncate max-w-full ${certClasses[cs]}`}>
                            {cs === "green" && (
                                <svg width="9" height="9" viewBox="0 0 10 10" className="flex-shrink-0">
                                    <path d="M1.5 5l3 3 4-5.5" stroke="currentColor" strokeWidth="1.8" fill="none" strokeLinecap="round" />
                                </svg>
                            )}
                            {product.certificate}
                        </span>
                    ) : (
                        <span className="inline-block h-[1.6rem]" aria-hidden />
                    )}
                </div>

                <div className="flex-1" />
                <button
                    onClick={e => { e.stopPropagation(); onClick(); }}
                    className="mt-2 w-full border-2 border-[#2A5DA8] text-[#2A5DA8] py-2.5 rounded-xl hover:bg-[#2A5DA8] hover:text-white transition-all text-sm font-bold tracking-wide"
                >
                    Know More →
                </button>
            </div>
        </div>
    );
}

// ─── ProductsInner ────────────────────────────────────────────────────────────

function ProductsInner() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const domainParam = searchParams?.get("domain") || "";

    const [selectedDomain, setSelectedDomain] = useState(domainParam);
    const [search, setSearch] = useState("");
    const [selectedCategory, setSelectedCategory] = useState("");
    const [selectedSubcategory, setSelectedSubcategory] = useState("");

    useEffect(() => {
        const d = searchParams?.get("domain") || "";
        setSelectedDomain(d);
        setSelectedCategory("");
        setSelectedSubcategory("");
        setSearch("");
    }, [searchParams]);

    const hero = selectedDomain ? domainHero[selectedDomain] : null;
    const isComingSoon = COMING_SOON_DOMAINS.has(selectedDomain);

    const activeFilterCount =
        (selectedCategory ? 1 : 0) +
        (selectedSubcategory ? 1 : 0) +
        (search.trim() ? 1 : 0);

    function clearAll() {
        setSearch("");
        setSelectedCategory("");
        setSelectedSubcategory("");
    }

    function handleSelectCategory(c: string) {
        setSelectedCategory(c);
        setSelectedSubcategory("");
    }

    const augmentedProducts = useMemo(
        () =>
            productsData.map(p =>
                isSanitizerProduct(p) ? { ...p, category: "Sanitizer", subcategory: "" } : p
            ),
        []
    );

    const domainProducts = useMemo(
        () => augmentedProducts.filter(p => !selectedDomain || p.domain === selectedDomain),
        [augmentedProducts, selectedDomain]
    );

    const visibleCategories = useMemo(() => {
        const fromTree = Object.keys(CATEGORY_TREE).filter(
            cat => cat !== "Sanitizer" && domainProducts.some(p => p.category === cat)
        );
        const hasSanitizer = domainProducts.some(p => p.category === "Sanitizer");
        return hasSanitizer ? [...fromTree, "Sanitizer"] : fromTree;
    }, [domainProducts]);

    const filteredProducts = useMemo(() => {
        let list = domainProducts;
        if (search.trim()) {
            const q = search.toLowerCase();
            list = list.filter(p =>
                p.name.toLowerCase().includes(q) ||
                p.composition.toLowerCase().includes(q) ||
                p.category.toLowerCase().includes(q) ||
                p.subcategory.toLowerCase().includes(q)
            );
        }
        if (selectedSubcategory) {
            list = list.filter(p => p.subcategory === selectedSubcategory);
        } else if (selectedCategory) {
            list = list.filter(p => p.category === selectedCategory);
        }
        return list;
    }, [domainProducts, search, selectedCategory, selectedSubcategory]);

    return (
        <div className="bg-[#f5f7fa] min-h-screen">

            {/* HERO */}
            <div className="relative h-[50vh] min-h-[320px] flex items-end overflow-hidden">
                {!selectedDomain && (
                    <img
                        src="/images/products_hero.png"
                        alt="Hero Background"
                        className="absolute inset-0 w-full h-full object-cover"
                    />
                )}
                {selectedDomain === "Aquaculture" && (
                    <video className="absolute inset-0 w-full h-full object-cover" autoPlay loop muted playsInline>
                        <source src="/videos/herr.mp4" type="video/mp4" />
                    </video>
                )}
                {selectedDomain === "Poultry" && (
                    <video className="absolute inset-0 w-full h-full object-cover" autoPlay loop muted playsInline>
                        <source src="/videos/poultry.mp4" type="video/mp4" />
                    </video>
                )}
                {selectedDomain === "Cattle" && (
                    <video className="absolute inset-0 w-full h-full object-cover" autoPlay loop muted playsInline>
                        <source src="/videos/cattle.mp4" type="video/mp4" />
                    </video>
                )}

                <div className={`absolute inset-0 bg-gradient-to-r ${hero ? hero.overlay : "from-[#0f172a]/90 via-[#1e3a8a]/70 to-[#0369a1]/40"}`} />
                <div className="absolute inset-0 overflow-hidden pointer-events-none">
                    <div className="absolute -right-20 top-1/2 -translate-y-1/2 w-96 h-96 rounded-full border-[60px] border-white/5" />
                    <div className="absolute right-32 -top-16 w-64 h-64 rounded-full border-[40px] border-white/5" />
                </div>

                <div className="relative z-10 max-w-7xl mx-auto px-8 pb-12 w-full">
                    <div className="relative overflow-hidden rounded-3xl flex items-center gap-2 text-white/60 text-xs mb-3 font-medium">
                        <span>Home</span><span>/</span><span>Products</span>
                        {selectedDomain && <><span>/</span><span className="text-white">{selectedDomain}</span></>}
                    </div>
                    <h1 className="text-5xl font-black text-white leading-none tracking-tight drop-shadow-lg">
                        {hero ? hero.title : "All Products"}
                    </h1>
                    <p className="mt-3 text-white/80 text-base max-w-xl">
                        {hero ? hero.tagline : "Solution to Aquaculture Health"}
                    </p>
                    <div className="flex gap-3 mt-5">
                        {isComingSoon ? (
                            <span className="bg-white/15 backdrop-blur-sm text-white text-xs font-semibold px-4 py-1.5 rounded-full border border-white/20 flex items-center gap-2">
                                <span className="w-1.5 h-1.5 rounded-full bg-white animate-pulse" />
                                Products Under Manufacturing
                            </span>
                        ) : (
                            <span className="bg-white/15 backdrop-blur-sm text-white text-xs font-semibold px-4 py-1.5 rounded-full border border-white/20">
                                {filteredProducts.length} Products
                            </span>
                        )}
                        {selectedDomain && (
                            <span className="bg-white/15 backdrop-blur-sm text-white text-xs font-semibold px-4 py-1.5 rounded-full border border-white/20">
                                {selectedDomain}
                            </span>
                        )}
                    </div>
                </div>
            </div>

            {/* DOMAIN TABS */}
            <div className="max-w-7xl mx-auto px-6 pt-6">
                <div className="flex gap-2 flex-wrap">
                    <button
                        onClick={() => { setSelectedDomain(""); clearAll(); }}
                        className={`px-5 py-2 rounded-full text-sm font-semibold border transition-all ${!selectedDomain ? "bg-[#2A5DA8] text-white border-[#2A5DA8] shadow-md" : "bg-white text-gray-600 border-gray-200 hover:border-[#2A5DA8] hover:text-[#2A5DA8]"}`}
                    >
                        All
                    </button>
                    {ALL_DOMAINS.map(domain => (
                        <button
                            key={domain}
                            onClick={() => { setSelectedDomain(domain); clearAll(); }}
                            className={`relative px-5 py-2 rounded-full text-sm font-semibold border transition-all ${selectedDomain === domain ? "bg-[#2A5DA8] text-white border-[#2A5DA8] shadow-md" : "bg-white text-gray-600 border-gray-200 hover:border-[#2A5DA8] hover:text-[#2A5DA8]"}`}
                        >
                            {domain}
                            {COMING_SOON_DOMAINS.has(domain) && (
                                <span className="absolute -top-1.5 -right-1.5 w-2.5 h-2.5 rounded-full bg-amber-400 border-2 border-white" title="Coming Soon" />
                            )}
                        </button>
                    ))}
                </div>
            </div>

            {/* SEARCH + LAYOUT */}
            <div className="max-w-7xl mx-auto px-6 py-6">

                {/* Search bar — hide when coming soon */}
                {!isComingSoon && (
                    <div className="relative mb-6">
                        <Search size={17} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                        <input
                            type="text" value={search} onChange={e => setSearch(e.target.value)}
                            placeholder="Search by product name, composition or category…"
                            className="w-full h-12 pl-11 pr-10 rounded-xl border border-gray-200 bg-white text-sm text-gray-800 placeholder-gray-400 outline-none focus:border-[#2A5DA8] focus:ring-2 focus:ring-[#2A5DA8]/10 transition-all shadow-sm"
                        />
                        {search && (
                            <button onClick={() => setSearch("")} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600">
                                <X size={15} />
                            </button>
                        )}
                    </div>
                )}

                {isComingSoon ? (
                    /* ── Coming Soon full-width layout (no sidebar) ── */
                    <ComingSoon domain={selectedDomain} />
                ) : (
                    /* ── Normal layout with sidebar + grid ── */
                    <div className="flex gap-6 items-start">

                        {/* SIDEBAR */}
                        <aside className="w-64 flex-shrink-0 bg-white rounded-2xl border border-gray-100 shadow-sm p-4 sticky top-24">
                            <div className="flex items-center justify-between mb-4 pb-3 border-b border-gray-100">
                                <div className="flex items-center gap-2">
                                    <SlidersHorizontal size={15} className="text-[#2A5DA8]" />
                                    <span className="font-bold text-gray-800 text-sm">Categories</span>
                                    {activeFilterCount > 0 && (
                                        <span className="w-5 h-5 rounded-full bg-[#2A5DA8] text-white text-[10px] font-bold flex items-center justify-center">
                                            {activeFilterCount}
                                        </span>
                                    )}
                                </div>
                                {activeFilterCount > 0 && (
                                    <button onClick={clearAll} className="text-[11px] text-[#2A5DA8] font-semibold hover:underline flex items-center gap-1">
                                        <X size={10} /> Reset
                                    </button>
                                )}
                            </div>

                            {(selectedCategory || selectedSubcategory) && (
                                <div className="mb-3 px-3 py-2 bg-blue-50 rounded-xl flex flex-wrap items-center gap-1 text-[11px]">
                                    {selectedCategory && (
                                        <button
                                            onClick={() => { setSelectedCategory(""); setSelectedSubcategory(""); }}
                                            className="flex items-center gap-1 text-[#2A5DA8] font-semibold hover:underline"
                                        >
                                            {selectedCategory} <X size={9} />
                                        </button>
                                    )}
                                    {selectedSubcategory && (
                                        <>
                                            <span className="text-gray-400">›</span>
                                            <button onClick={() => setSelectedSubcategory("")} className="flex items-center gap-1 text-sky-600 font-semibold hover:underline">
                                                {selectedSubcategory} <X size={9} />
                                            </button>
                                        </>
                                    )}
                                </div>
                            )}

                            <div className="flex flex-col gap-0.5 max-h-[60vh] overflow-y-auto pr-0.5">
                                {visibleCategories.map(cat => (
                                    <CategoryFilterSection
                                        key={cat}
                                        category={cat}
                                        subcategories={CATEGORY_TREE[cat] || []}
                                        selectedCategory={selectedCategory}
                                        selectedSubcategory={selectedSubcategory}
                                        onSelectCategory={handleSelectCategory}
                                        onSelectSubcategory={setSelectedSubcategory}
                                        domainProducts={domainProducts}
                                    />
                                ))}
                            </div>
                        </aside>

                        {/* PRODUCT GRID */}
                        <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between mb-5">
                                <p className="text-sm text-gray-500">
                                    Showing <span className="font-bold text-gray-800">{filteredProducts.length}</span> product{filteredProducts.length !== 1 ? "s" : ""}
                                    {selectedSubcategory
                                        ? <> in <span className="text-[#2A5DA8] font-semibold"> {selectedSubcategory}</span></>
                                        : selectedCategory
                                            ? <> in <span className="text-[#2A5DA8] font-semibold"> {selectedCategory}</span></>
                                            : selectedDomain
                                                ? <> in <span className="text-[#2A5DA8] font-semibold"> {selectedDomain}</span></>
                                                : null
                                    }
                                    {search && <> for "<span className="text-[#2A5DA8] font-semibold">{search}</span>"</>}
                                </p>
                                {activeFilterCount > 0 && (
                                    <button onClick={clearAll} className="flex items-center gap-1.5 text-xs text-[#2A5DA8] font-semibold border border-[#2A5DA8]/30 px-3 py-1.5 rounded-lg hover:bg-[#2A5DA8]/5 transition-colors">
                                        <X size={11} /> Reset Filters
                                    </button>
                                )}
                            </div>

                            {filteredProducts.length === 0 ? (
                                <div className="flex flex-col items-center justify-center py-32 bg-white rounded-2xl border border-gray-100 text-gray-400">
                                    <div className="w-20 h-20 rounded-full bg-gray-100 flex items-center justify-center mb-4">
                                        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#9ca3af" strokeWidth="1.5">
                                            <circle cx="11" cy="11" r="8" /><path d="m21 21-4.35-4.35" />
                                        </svg>
                                    </div>
                                    <p className="font-semibold text-base text-gray-500 mb-1">No products found</p>
                                    <p className="text-sm text-gray-400 mb-5">Try adjusting your filters or search term.</p>
                                    <button onClick={clearAll} className="px-5 py-2 rounded-xl bg-[#2A5DA8] text-white text-sm font-semibold hover:bg-[#1e4a8a] transition-colors">
                                        Clear All Filters
                                    </button>
                                </div>
                            ) : (
                                <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-3">
                                    {filteredProducts.map(product => (
                                        <ProductCard
                                            key={product.id}
                                            product={product}
                                            onClick={() => router.push(`/products/${product.id}`)}
                                        />
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>

            <Footer />
        </div>
    );
}

// ─── Page export ──────────────────────────────────────────────────────────────

export default function ProductsPage() {
    return (
        <Suspense fallback={
            <div className="min-h-screen flex items-center justify-center">
                <div className="w-8 h-8 border-4 border-[#2A5DA8] border-t-transparent rounded-full animate-spin" />
            </div>
        }>
            <ProductsInner />
        </Suspense>
    );
}